class Subject:
    def __init__(self):
        self._obs = []
    def attach(self, o):
        self._obs.append(o)
    def notify(self, state):
        for o in self._obs:
            o.update(state)

class Obs:
    def __init__(self, name):
        self.name = name
    def update(self, state):
        print(f"{self.name}:{state}")

s = Subject()
s.attach(Obs("a"))
s.attach(Obs("b"))
s.notify(1)

